def is_woodall(n):
    if not isinstance(n, int):
        return False
    if n < 2:
        return False
    s = str(n)
    if s != s[::-1]:
        return False
    def is_prime(num):
        if num < 2:
            return False
        for i in range(2, int(num**0.5)+1):
            if num % i == 0:
                return False
        return True
    return is_prime(n)

# Test cases
assert is_woodall(383) == True
assert is_woodall(254) == False
assert is_woodall(200) == False
